import { useEffect, useState } from "react";
import API from "../services/api";
import "../styles/ComparePlayers.css";

function ComparePlayers() {
  const [players, setPlayers] = useState([]);
  const [player1, setPlayer1] = useState(null);
  const [player2, setPlayer2] = useState(null);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    API.get("/players").then((res) => setPlayers(res.data));
  }, []);

  useEffect(() => {
    if (player1 && player2) {
      setIsVisible(false);
      const timer = setTimeout(() => setIsVisible(true), 100);
      return () => clearTimeout(timer);
    }
  }, [player1, player2]);

  const handleSelect1 = (e) => {
    const player = players.find((p) => p._id === e.target.value);
    setPlayer1(player);
  };

  const handleSelect2 = (e) => {
    const player = players.find((p) => p._id === e.target.value);
    setPlayer2(player);
  };

  const getWinner = (p1, p2) => {
    const metrics = [
      { p1: p1.runs || 0, p2: p2.runs || 0 },
      { p1: p1.battingAvg || 0, p2: p2.battingAvg || 0 },
      { p1: p1.strikeRate || 0, p2: p2.strikeRate || 0 },
      { p1: p1.matches || 0, p2: p2.matches || 0 },
      { p1: p1.highScore || 0, p2: p2.highScore || 0 },
      { p1: p1.wickets || 0, p2: p2.wickets || 0 }
    ];

    let p1Wins = 0, p2Wins = 0;

    metrics.forEach(metric => {
      if (metric.p1 > metric.p2) p1Wins++;
      else if (metric.p2 > metric.p1) p2Wins++;
    });

    if (p1Wins > p2Wins) return { winner: p1.name, winnerId: 1 };
    if (p2Wins > p1Wins) return { winner: p2.name, winnerId: 2 };
    return { winner: "Tie", winnerId: 0 };
  };

  const StatRow = ({ label, val1, val2, index }) => (
    <div className="compare-stat-row" style={{ animationDelay: `${index * 0.1}s` }}>
      <div className={`stat-val p1-stat ${val1 > val2 ? 'winner' : ''}`}>
        {val1}
        {val1 > val2 && <span className="stat-indicator">▲</span>}
      </div>
      <div className="stat-label">{label}</div>
      <div className={`stat-val p2-stat ${val2 > val1 ? 'winner' : ''}`}>
        {val2}
        {val2 > val1 && <span className="stat-indicator">▲</span>}
      </div>
    </div>
  );

  return (
    <div className="compare-page-container">
      <div className="compare-hero">
        <div className="hero-content">
          <h1>PLAYER <span className="vs-glow">VS</span> COMPARISON</h1>
          <p>Analyze and compare player performance across formats</p>
        </div>
        <div className="compare-hero-glow"></div>
      </div>

      <div className="compare-selectors-wrapper">
        <div className="selector-box p1-selector">
          <label>PLAYER 1</label>
          <div className="select-glow">
            <select onChange={handleSelect1} value={player1?._id || ""}>
              <option value="">Choose Player</option>
              {players.map((p) => (
                <option key={p._id} value={p._id}>{p.name}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="compare-vs-badge">VS</div>

        <div className="selector-box p2-selector">
          <label>PLAYER 2</label>
          <div className="select-glow">
            <select onChange={handleSelect2} value={player2?._id || ""}>
              <option value="">Choose Player</option>
              {players.map((p) => (
                <option key={p._id} value={p._id}>{p.name}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {player1 && player2 ? (
        <div className={`compare-results-section ${isVisible ? 'fade-in' : ''}`}>
          <div className="battle-card">
            <div className="battle-header">
              <div className="battle-player p1-header">
                <div className="player-avatar-small">{player1.name.charAt(0)}</div>
                <div className="player-meta">
                  <h3>{player1.name}</h3>
                  <span className="team-pill">{player1.team}</span>
                </div>
              </div>

              <div className="battle-divider">⚡</div>

              <div className="battle-player p2-header">
                <div className="player-meta">
                  <h3>{player2.name}</h3>
                  <span className="team-pill">{player2.team}</span>
                </div>
                <div className="player-avatar-small">{player2.name.charAt(0)}</div>
              </div>
            </div>

            <div className="battle-stats-grid">
              <StatRow index={0} label="Runs" val1={player1.runs || 0} val2={player2.runs || 0} />
              <StatRow index={1} label="Average" val1={player1.battingAvg || 0} val2={player2.battingAvg || 0} />
              <StatRow index={2} label="Strike Rate" val1={player1.strikeRate || 0} val2={player2.strikeRate || 0} />
              <StatRow index={3} label="Matches" val1={player1.matches || 0} val2={player2.matches || 0} />
              <StatRow index={4} label="Highest Score" val1={player1.highScore || 0} val2={player2.highScore || 0} />
              <StatRow index={5} label="Wickets" val1={player1.wickets || 0} val2={player2.wickets || 0} />
            </div>
          </div>

          <div className="comparison-winner-reveal">
            {(() => {
              const result = getWinner(player1, player2);
              if (result.winnerId === 0) {
                return (
                  <div className="winner-result tie-result">
                    <div className="winner-icon-glow">🤝</div>
                    <h2>IT'S A DEADLOCK!</h2>
                    <p>Both legends are perfectly matched</p>
                  </div>
                );
              } else {
                const winner = result.winnerId === 1 ? player1 : player2;
                return (
                  <div className={`winner-result winner-${result.winnerId}-result`}>
                    <div className="winner-label">ANALYSIS COMPLETE</div>
                    <div className="winner-name-glow">
                        <span className="trophy-val">🏆</span>
                        <h2>{winner.name.toUpperCase()}</h2>
                    </div>
                    <p>Dominates in {result.winnerId === 1 ? 'Player 1' : 'Player 2'} favor</p>
                  </div>
                );
              }
            })()}
          </div>
        </div>
      ) : (
        <div className="compare-placeholder">
          <div className="placeholder-icon">⚖️</div>
          <p>SELECT TWO PLAYERS TO START THE ANALYTICAL BATTLE</p>
        </div>
      )}
    </div>
  );
}

export default ComparePlayers;
